"use client";

import { useState, useEffect, useCallback } from "react";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Download,
  Eye,
  Loader2,
  ChevronLeft,
  ChevronRight,
  RefreshCw,
  ExternalLink,
} from "lucide-react";
import { useAuth } from "@/contexts/auth-context";
import {
  transactionApi,
  Transaction,
  TransactionFilters,
  PaginatedResponse,
} from "@/lib/portal-api";
import { useRouter } from "next/navigation";

// Helper Functions
function formatCurrency(amount: string, currency: string): string {
  const num = parseFloat(amount);
  if (currency === "VND") {
    return new Intl.NumberFormat("vi-VN", {
      style: "currency",
      currency: "VND",
      minimumFractionDigits: 0,
      maximumFractionDigits: 0,
    }).format(num);
  }
  return (
    new Intl.NumberFormat("en-US", {
      minimumFractionDigits: 2,
      maximumFractionDigits: 8,
    }).format(num) + ` ${currency}`
  );
}

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString("vi-VN", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
}

function getStatusColor(status: string): string {
  switch (status) {
    case "COMPLETED":
      return "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400";
    case "PENDING":
    case "PROCESSING":
      return "bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400";
    case "FAILED":
    case "CANCELLED":
      return "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400";
    default:
      return "bg-gray-100 text-gray-800 dark:bg-gray-800 dark:text-gray-300";
  }
}

function getTypeLabel(type: string): string {
  switch (type) {
    case "DEPOSIT":
      return "Deposit";
    case "WITHDRAW":
      return "Withdraw";
    case "TRADE":
      return "Trade";
    default:
      return type;
  }
}

export default function TransactionsPage() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [pagination, setPagination] = useState({
    page: 1,
    perPage: 10,
    total: 0,
    totalPages: 0,
  });
  const [filters, setFilters] = useState<TransactionFilters>({
    type: undefined,
    status: undefined,
    startDate: undefined,
    endDate: undefined,
  });
  const [search, setSearch] = useState("");
  const [selectedTx, setSelectedTx] = useState<Transaction | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);

  const { isAuthenticated, isLoading: authLoading } = useAuth();
  const router = useRouter();

  // Redirect if not authenticated
  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      router.push("/portal/login");
    }
  }, [authLoading, isAuthenticated, router]);

  // Fetch transactions
  const fetchTransactions = useCallback(
    async (showRefreshing = false) => {
      if (showRefreshing) {
        setIsRefreshing(true);
      } else {
        setIsLoading(true);
      }

      try {
        const response: PaginatedResponse<Transaction> =
          await transactionApi.listTransactions({
            ...filters,
            page: pagination.page,
            perPage: pagination.perPage,
          });

        setTransactions(response.data);
        setPagination((prev) => ({
          ...prev,
          total: response.total,
          totalPages: response.totalPages,
        }));
      } catch {
        // Failed to fetch transactions silently
      } finally {
        setIsLoading(false);
        setIsRefreshing(false);
      }
    },
    [filters, pagination.page, pagination.perPage]
  );

  useEffect(() => {
    if (isAuthenticated) {
      fetchTransactions();
    }
  }, [isAuthenticated, fetchTransactions]);

  // Filter transactions by search (client-side for reference field)
  const filteredTransactions = transactions.filter((tx) => {
    if (search) {
      return (
        tx.id.toLowerCase().includes(search.toLowerCase()) ||
        tx.reference.toLowerCase().includes(search.toLowerCase())
      );
    }
    return true;
  });

  const handlePageChange = (newPage: number) => {
    setPagination((prev) => ({ ...prev, page: newPage }));
  };

  const handleFilterChange = (key: keyof TransactionFilters, value: string) => {
    setFilters((prev) => ({
      ...prev,
      [key]: value === "ALL" ? undefined : value,
    }));
    setPagination((prev) => ({ ...prev, page: 1 }));
  };

  const handleExport = () => {
    const headers = [
      "Date",
      "Type",
      "Amount",
      "Currency",
      "Status",
      "Reference",
    ];
    const csvContent = [
      headers.join(","),
      ...filteredTransactions.map((tx) =>
        [
          tx.createdAt,
          tx.type,
          tx.amount,
          tx.currency,
          tx.status,
          tx.reference,
        ].join(",")
      ),
    ].join("\n");

    const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute(
      "download",
      `transactions_${new Date().toISOString()}.csv`
    );
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Show loading state
  if (authLoading || isLoading) {
    return (
      <div className="space-y-6 p-6">
        <div className="flex items-center justify-center py-20">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 p-6">
      <div className="flex flex-col gap-2">
        <h1 className="text-3xl font-bold tracking-tight">Transaction History</h1>
        <p className="text-muted-foreground">
          View and manage your deposits, withdrawals, and trades.
        </p>
      </div>

      {/* Controls & Filters */}
      <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between bg-card p-4 rounded-lg border">
        <div className="flex flex-1 flex-col gap-4 md:flex-row md:items-center">
          <Input
            placeholder="Search reference..."
            className="w-full md:w-[250px]"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />

          <Select
            value={filters.type || "ALL"}
            onValueChange={(value) => handleFilterChange("type", value)}
          >
            <SelectTrigger className="w-full md:w-[150px]">
              <SelectValue placeholder="All Types" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="ALL">All Types</SelectItem>
              <SelectItem value="DEPOSIT">Deposit</SelectItem>
              <SelectItem value="WITHDRAW">Withdraw</SelectItem>
              <SelectItem value="TRADE">Trade</SelectItem>
            </SelectContent>
          </Select>

          <Select
            value={filters.status || "ALL"}
            onValueChange={(value) => handleFilterChange("status", value)}
          >
            <SelectTrigger className="w-full md:w-[150px]">
              <SelectValue placeholder="All Statuses" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="ALL">All Statuses</SelectItem>
              <SelectItem value="COMPLETED">Completed</SelectItem>
              <SelectItem value="PENDING">Pending</SelectItem>
              <SelectItem value="PROCESSING">Processing</SelectItem>
              <SelectItem value="FAILED">Failed</SelectItem>
              <SelectItem value="CANCELLED">Cancelled</SelectItem>
            </SelectContent>
          </Select>

          <Input
            type="date"
            className="w-full md:w-[150px]"
            value={filters.startDate || ""}
            onChange={(e) => handleFilterChange("startDate", e.target.value)}
            placeholder="From date"
          />
        </div>

        <div className="flex gap-2">
          <Button
            variant="outline"
            size="icon"
            onClick={() => fetchTransactions(true)}
            disabled={isRefreshing}
          >
            <RefreshCw
              className={`h-4 w-4 ${isRefreshing ? "animate-spin" : ""}`}
            />
          </Button>
          <Button variant="outline" onClick={handleExport}>
            <Download className="mr-2 h-4 w-4" />
            Export CSV
          </Button>
        </div>
      </div>

      {/* Transaction Table */}
      <div className="rounded-md border bg-card">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Date</TableHead>
              <TableHead>Reference</TableHead>
              <TableHead>Type</TableHead>
              <TableHead className="text-right">Amount</TableHead>
              <TableHead>Status</TableHead>
              <TableHead className="w-[50px]"></TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {filteredTransactions.length > 0 ? (
              filteredTransactions.map((tx) => (
                <TableRow key={tx.id}>
                  <TableCell className="font-medium">
                    {formatDate(tx.createdAt)}
                  </TableCell>
                  <TableCell className="font-mono text-sm">
                    {tx.reference}
                  </TableCell>
                  <TableCell>
                    <span className="inline-flex items-center font-medium">
                      {getTypeLabel(tx.type)}
                    </span>
                  </TableCell>
                  <TableCell className="text-right font-mono">
                    {formatCurrency(tx.amount, tx.currency)}
                  </TableCell>
                  <TableCell>
                    <span
                      className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${getStatusColor(
                        tx.status
                      )}`}
                    >
                      {tx.status}
                    </span>
                  </TableCell>
                  <TableCell>
                    <Dialog>
                      <DialogTrigger asChild>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => setSelectedTx(tx)}
                        >
                          <Eye className="h-4 w-4" />
                        </Button>
                      </DialogTrigger>
                      <DialogContent>
                        <DialogHeader>
                          <DialogTitle>Transaction Details</DialogTitle>
                          <DialogDescription>
                            Detailed information about this transaction.
                          </DialogDescription>
                        </DialogHeader>
                        {selectedTx && (
                          <div className="grid gap-4 py-4">
                            <div className="grid grid-cols-4 items-center gap-4">
                              <span className="text-sm font-medium text-muted-foreground text-right">
                                Reference
                              </span>
                              <span className="col-span-3 font-mono text-sm">
                                {selectedTx.reference}
                              </span>
                            </div>
                            <div className="grid grid-cols-4 items-center gap-4">
                              <span className="text-sm font-medium text-muted-foreground text-right">
                                Date
                              </span>
                              <span className="col-span-3 text-sm">
                                {formatDate(selectedTx.createdAt)}
                              </span>
                            </div>
                            <div className="grid grid-cols-4 items-center gap-4">
                              <span className="text-sm font-medium text-muted-foreground text-right">
                                Type
                              </span>
                              <span className="col-span-3 text-sm font-medium">
                                {getTypeLabel(selectedTx.type)}
                              </span>
                            </div>
                            <div className="grid grid-cols-4 items-center gap-4">
                              <span className="text-sm font-medium text-muted-foreground text-right">
                                Amount
                              </span>
                              <span className="col-span-3 font-mono text-sm font-bold">
                                {formatCurrency(
                                  selectedTx.amount,
                                  selectedTx.currency
                                )}
                              </span>
                            </div>
                            {selectedTx.fee && (
                              <div className="grid grid-cols-4 items-center gap-4">
                                <span className="text-sm font-medium text-muted-foreground text-right">
                                  Fee
                                </span>
                                <span className="col-span-3 font-mono text-sm">
                                  {formatCurrency(
                                    selectedTx.fee,
                                    selectedTx.currency
                                  )}
                                </span>
                              </div>
                            )}
                            <div className="grid grid-cols-4 items-center gap-4">
                              <span className="text-sm font-medium text-muted-foreground text-right">
                                Status
                              </span>
                              <span className="col-span-3">
                                <span
                                  className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${getStatusColor(
                                    selectedTx.status
                                  )}`}
                                >
                                  {selectedTx.status}
                                </span>
                              </span>
                            </div>
                            {selectedTx.details && (
                              <div className="grid grid-cols-4 items-center gap-4">
                                <span className="text-sm font-medium text-muted-foreground text-right">
                                  Details
                                </span>
                                <span className="col-span-3 text-sm">
                                  {selectedTx.details}
                                </span>
                              </div>
                            )}
                            {selectedTx.txHash && (
                              <div className="grid grid-cols-4 items-center gap-4">
                                <span className="text-sm font-medium text-muted-foreground text-right">
                                  Tx Hash
                                </span>
                                <span className="col-span-3 flex items-center gap-2">
                                  <span className="font-mono text-xs text-muted-foreground truncate max-w-[200px]">
                                    {selectedTx.txHash}
                                  </span>
                                  <a
                                    href={`https://tronscan.org/#/transaction/${selectedTx.txHash}`}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="text-primary hover:underline"
                                  >
                                    <ExternalLink className="h-4 w-4" />
                                  </a>
                                </span>
                              </div>
                            )}
                            <div className="grid grid-cols-4 items-center gap-4">
                              <span className="text-sm font-medium text-muted-foreground text-right">
                                ID
                              </span>
                              <span className="col-span-3 font-mono text-xs text-muted-foreground">
                                {selectedTx.id}
                              </span>
                            </div>
                          </div>
                        )}
                      </DialogContent>
                    </Dialog>
                  </TableCell>
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell colSpan={6} className="h-24 text-center">
                  No transactions found.
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </div>

      {/* Pagination */}
      <div className="flex items-center justify-between py-4">
        <p className="text-sm text-muted-foreground">
          Showing{" "}
          {Math.min(
            (pagination.page - 1) * pagination.perPage + 1,
            pagination.total
          )}{" "}
          to {Math.min(pagination.page * pagination.perPage, pagination.total)}{" "}
          of {pagination.total} transactions
        </p>
        <div className="flex items-center space-x-2">
          <Button
            variant="outline"
            size="sm"
            onClick={() => handlePageChange(pagination.page - 1)}
            disabled={pagination.page <= 1}
          >
            <ChevronLeft className="h-4 w-4" />
            Previous
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={() => handlePageChange(pagination.page + 1)}
            disabled={pagination.page >= pagination.totalPages}
          >
            Next
            <ChevronRight className="h-4 w-4" />
          </Button>
        </div>
      </div>
    </div>
  );
}
